import { useState, useEffect } from 'react';
import axiosInstance from '../axiosConfig';
import { useAuth } from '../context/AuthContext';

const Bookings = () => {
  const { user } = useAuth();
  const [bookings, setBookings] = useState([]);
  const [formData, setFormData] = useState({
    serviceType: '',
    quantity: '',
    bookingDate: '',
    collectionMethod: '',
    returnMethod: '',
  });

  const fetchBookings = async () => {
    try {
      const response = await axiosInstance.get('/api/bookings', {
        headers: { Authorization: `Bearer ${user.token}` },
      });
      setBookings(response.data);
    } catch (error) {
      console.error(error);
      alert('Failed to fetch bookings.');
    }
  };

  useEffect(() => {
    if (user?.token) {
      fetchBookings();
    }
  }, [user]);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleCreateBooking = async (e) => {
    e.preventDefault();

    try {
      const response = await axiosInstance.post('/api/bookings', formData, {
        headers: { Authorization: `Bearer ${user.token}` },
      });

      setBookings([...bookings, response.data]);
      setFormData({
        serviceType: '',
        quantity: '',
        bookingDate: '',
        collectionMethod: '',
        returnMethod: '',
      });

      alert('Booking created successfully');
    } catch (error) {
      console.error(error);
      alert(error.response?.data?.message || 'Failed to create booking.');
    }
  };

  const handleDeleteBooking = async (id) => {
    try {
      await axiosInstance.delete(`/api/bookings/${id}`, {
        headers: { Authorization: `Bearer ${user.token}` },
      });

      setBookings(bookings.filter((booking) => booking._id !== id));
      alert('Booking deleted successfully');
    } catch (error) {
      console.error(error);
      alert('Failed to delete booking.');
    }
  };

  const handleStatusUpdate = async (id, newStatus) => {
    try {
      const response = await axiosInstance.put(
        `/api/bookings/${id}`,
        { status: newStatus },
        {
          headers: { Authorization: `Bearer ${user.token}` },
        }
      );

      setBookings(
        bookings.map((booking) =>
          booking._id === id ? response.data : booking
        )
      );

      alert('Status updated successfully');
    } catch (error) {
      console.error(error);
      alert('Failed to update status.');
    }
  };

  return (
    <div className="container mx-auto p-6">
      <h1 className="text-3xl font-bold mb-6">Laundry Booking CRUD</h1>

      <form onSubmit={handleCreateBooking} className="bg-white p-6 shadow-md rounded mb-8">
        <h2 className="text-xl font-semibold mb-4">Create Booking</h2>

        <select
          name="serviceType"
          value={formData.serviceType}
          onChange={handleChange}
          className="w-full mb-4 p-2 border rounded"
          required
        >
          <option value="">Select Service Type</option>
          <option value="Wash & Fold">Wash & Fold</option>
          <option value="Wash & Ironing">Wash & Ironing</option>
          <option value="Dry Cleaning">Dry Cleaning</option>
          <option value="Ironing">Ironing</option>
        </select>

        <input
          type="number"
          name="quantity"
          placeholder="Quantity"
          value={formData.quantity}
          onChange={handleChange}
          className="w-full mb-4 p-2 border rounded"
          required
        />

        <input
          type="date"
          name="bookingDate"
          value={formData.bookingDate}
          onChange={handleChange}
          className="w-full mb-4 p-2 border rounded"
          required
        />

        <select
          name="collectionMethod"
          value={formData.collectionMethod}
          onChange={handleChange}
          className="w-full mb-4 p-2 border rounded"
          required
        >
          <option value="">Select Collection Method</option>
          <option value="Drop off at store">Drop off at store</option>
          <option value="Pickup from home">Pickup from home</option>
        </select>

        <select
          name="returnMethod"
          value={formData.returnMethod}
          onChange={handleChange}
          className="w-full mb-4 p-2 border rounded"
          required
        >
          <option value="">Select Return Method</option>
          <option value="Pick up at store">Pick up at store</option>
          <option value="Home delivery">Home delivery</option>
        </select>

        <button type="submit" className="w-full bg-grey-600 text-white p-2 rounded">
          Create Booking
        </button>
      </form>

      <div className="bg-white p-6 shadow-md rounded">
        <h2 className="text-xl font-semibold mb-4">My Bookings</h2>

        {bookings.length === 0 ? (
          <p>No bookings found.</p>
        ) : (
          bookings.map((booking) => (
            <div key={booking._id} className="border p-4 rounded mb-4">
              <p><strong>Service Type:</strong> {booking.serviceType}</p>
              <p><strong>Quantity:</strong> {booking.quantity}</p>
              <p><strong>Booking Date:</strong> {new Date(booking.bookingDate).toLocaleDateString()}</p>
              <p><strong>Collection Method:</strong> {booking.collectionMethod}</p>
              <p><strong>Return Method:</strong> {booking.returnMethod}</p>
              <p><strong>Status:</strong> {booking.status}</p>
              <p><strong>Total Price:</strong> ${booking.totalPrice}</p>

              <div className="mt-4 flex gap-3">

                {user?.role === 'admin' && (
                <select
                  value={booking.status}
                  onChange={(e) => handleStatusUpdate(booking._id, e.target.value)}
                  className="p-2 border rounded"
                >
                  <option value="booked">booked</option>
                  <option value="waiting_pickup">waiting_pickup</option>
                  <option value="waiting_dropoff">waiting_dropoff</option>
                  <option value="laundry_received">laundry_received</option>
                  <option value="processing">processing</option>
                  <option value="ready">ready</option>
                  <option value="out_for_delivery">out_for_delivery</option>
                  <option value="completed">completed</option>
                </select>
                )}

                <button
                  onClick={() => handleDeleteBooking(booking._id)}
                  className="bg-red-600 text-white px-4 py-2 rounded"
                >
                  Delete
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default Bookings;
